mapper.select:
select nvl(max(REVISION_NO), 0)
from EVALUATION_HISTORY
where EVALUATION_NO = #{evaluationNo}

mapper.insert:
insert all

    into EVALUATION_SCORE(EVALUATION_NO, ITEM_NO, SCORE, RESON)
    values (
      #{evaluationNo}
      ,#{item.itemNo}
      ,#{item.score}
      ,#{item.reson}
    )

select 1 from dual

insert all

    into EVALUATION_SCORE_HISTORY(HISTORY_NO, ITEM_NO, SCORE, RESON)
    values (
      #{historyNo}
      ,#{item.itemNo}
      ,#{item.score}
      ,#{item.reson}
    )

select 1 from dual

mapper.update:
update EVALUATION_SCORE
set
  SCORE = #{insertScore.score}
  ,RESON = #{insertScore.reson}
where EVALUATION_NO = #{evaluationNo}
and ITEM_NO = (
  select ITEM_NO
  from EVALUATION_ITEM
  where FIELD = #{insertScore.field}
)

mapper.select:
select TARGET.HISTORY_NO ,TARGET.REVISION_NO ,TARGET.UPDATE_AT ,TARGET.ACTION_RESON ,TARGET.NICKNAME ,ESH_ITEM.SCORE ,ESH_ITEM.RESON ,ESH_ITEM.ITEM_NO ,ESH_ITEM.FIELD ,ED.MEMO ,FI.FILE_NO ,FI.ORIGINAL_NAME ,FI.FILE_SIZE from ( select EH.HISTORY_NO ,EH.REVISION_NO ,EH.UPDATE_AT ,EH.ACTION_RESON ,M.NICKNAME ,row_number() over (order by EH.REVISION_NO desc) as HRN from EVALUATION_HISTORY EH left join MEMBER M on (M.MEMBER_NO = EH.EVALUATE_BY)
left join EVALUATION E on (E.EVALUATION_NO = EH.EVALUATION_NO) left join COMPANY C on (C.COMPANY_NO = E.EVALUATION_NO)
where EH.EVALUATION_NO = #{companyNo} and EH.REVISION_NO <= #{revisionNo}
and C.STATUS = 'ACTIVE'
) TARGET inner join ( select ESH2.SCORE ,ESH2.RESON ,EI2.ITEM_NO ,EI2.FIELD ,EH2.HISTORY_NO ,row_number() over ( partition by ESH2.ITEM_NO order by EH2.REVISION_NO desc ) as RN from EVALUATION_HISTORY EH2 inner join EVALUATION_SCORE_HISTORY ESH2 on (ESH2.HISTORY_NO = EH2.HISTORY_NO) inner join EVALUATION_ITEM EI2 on (EI2.ITEM_NO = ESH2.ITEM_NO) where EH2.EVALUATION_NO = #{companyNo} and EH2.REVISION_NO <= #{revisionNo} ) ESH_ITEM on (ESH_ITEM.RN = 1) left join EVALUATION_DOC ED on (ED.HISTORY_NO = TARGET.HISTORY_NO) left join FILE_INFO FI on (FI.FILE_NO = ED.FILE_NO) where TARGET.HRN = 1

select nvl(max(HISTORY_NO), 0)
from EVALUATION_HISTORY
where EVALUATION_NO = #{evaluationNo}
